table.sql:
create temporary table temp_art as select * from STK_ARTICULOS where STK_ARTICULOS.id_stkarticulo= '[__id_stkarticulo__]';
update temp_art set id_stkarticulo = '[__stkarticulo_destino_id__]';
REPLACE INTO STK_ARTICULOS select * from temp_art;
drop temporary table temp_art;
delete from STK_ARTICULOS where id_stkarticulo = '[__id_stkarticulo__]';
